import React from 'react';

const Testimonials = () => (
    <section style={{ padding: '60px 80px', background: '#080402', borderTop: '1px solid #262626' }}>
        <h2 style={{ textAlign: 'center', color: '#fef3c7', marginBottom: '40px', fontWeight: '800' }}>Apa Kata Mereka?</h2>
        <div style={{ maxWidth: '600px', margin: '0 auto', padding: '40px', background: '#120b06', border: '1px solid #262626', borderRadius: '16px', textAlign: 'center' }}>
            <p style={{ color: '#a3a3a3', fontStyle: 'italic', lineHeight: '1.6' }}>"Berkat PasukanYerusSolo, saya mendapatkan pekerjaan impian saya di Solo hanya dalam waktu 2 minggu. Prosesnya sangat mudah!"</p>
            <p style={{ marginTop: '20px', fontWeight: '800', color: '#ea580c' }}>- Budi, Fullstack Developer</p>
        </div>
    </section>
);
export default Testimonials;
